/*@ Extern Coq (problem_50_pre: list Z -> Prop)
               (problem_50_encode_spec: list Z -> list Z -> Prop)
               (problem_50_spec: list Z -> list Z -> Prop)
               (problem_50_decode_spec: list Z -> list Z -> Prop)
               (encode_shift_char: Z -> Z)
               (decode_shift_char: Z -> Z)
               (ascii_range: list Z -> Prop) */
/*@ Import Coq Require Import p050_decode_shift */

char *malloc_char_array(int n)
/*@ Require n > 0 && emp
    Ensure __return != 0 && CharArray::undef_full(__return, n)
*/
;

int strlen(char *s)
/*@ With l n
    Require 0 <= n && n < INT_MAX &&
            Zlength(l) == n &&
            (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
            CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure __return == n &&
           (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
           CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
;

char *encode_shift(char *s)
/*@ With l len
    Require 0 <= len && len < INT_MAX &&
            Zlength(l) == len &&
            problem_50_pre(l) &&
            ascii_range(l) &&
            (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
            CharArray::full(s, len + 1, app(l, cons(0, nil)))
    Ensure exists out_l,
            (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
            (forall (k: Z), (0 <= k && k < len) => Znth(k, out_l, 0) != 0) &&
            Zlength(out_l) == len &&
            problem_50_encode_spec(l, out_l) &&
            CharArray::full(s, len + 1, app(l, cons(0, nil))) *
            CharArray::full(__return, len + 1, app(out_l, cons(0, nil)))
*/
{
    int i;
    int n = strlen(s) /*@ where l = l, n = len */;
    char *out = malloc_char_array(n + 1);

    /*@ Inv Assert exists out_l,
        0 <= i && i <= n &&
        n == len &&
        Zlength(l) == len &&
        0 <= len && len < INT_MAX &&
        problem_50_pre(l) &&
        ascii_range(l) &&
        Zlength(out_l) == i &&
        (forall (k: Z), (0 <= k && k < i) =>
            Znth(k, out_l, 0) == encode_shift_char(Znth(k, l, 0))) &&
        (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
        s == s@pre &&
        CharArray::full(s@pre, len + 1, app(l, cons(0, nil))) *
        CharArray::full(out, i, out_l) *
        CharArray::undef_seg(out, i, n + 1)
    */
    for (i = 0; i < n; i++) {
        int w = (s[i] + 5 - 97) % 26 + 97;
        out[i] = w;
    }
    out[n] = 0;
    return out;
}

char *p050_decode_shift(char *s)
/*@ With l len
    Require 0 <= len && len < INT_MAX &&
            Zlength(l) == len &&
            problem_50_pre(l) &&
            ascii_range(l) &&
            (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
            CharArray::full(s, len + 1, app(l, cons(0, nil)))
    Ensure exists out_l,
            (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
            (forall (k: Z), (0 <= k && k < len) => Znth(k, out_l, 0) != 0) &&
            Zlength(out_l) == len &&
            problem_50_decode_spec(l, out_l) &&
            CharArray::full(s, len + 1, app(l, cons(0, nil))) *
            CharArray::full(__return, len + 1, app(out_l, cons(0, nil)))
*/
{
    int i;
    int n = strlen(s) /*@ where l = l, n = len */;
    char *out = malloc_char_array(n + 1);

    /*@ Inv Assert exists out_l,
        0 <= i && i <= n &&
        n == len &&
        Zlength(l) == len &&
        0 <= len && len < INT_MAX &&
        problem_50_pre(l) &&
        ascii_range(l) &&
        Zlength(out_l) == i &&
        (forall (k: Z), (0 <= k && k < i) =>
            Znth(k, out_l, 0) == decode_shift_char(Znth(k, l, 0))) &&
        (forall (k: Z), (0 <= k && k < len) => Znth(k, l, 0) != 0) &&
        s == s@pre &&
        CharArray::full(s@pre, len + 1, app(l, cons(0, nil))) *
        CharArray::full(out, i, out_l) *
        CharArray::undef_seg(out, i, n + 1)
    */
    for (i = 0; i < n; i++) {
        int w = (s[i] + 21 - 97) % 26 + 97;
        out[i] = w;
    }
    out[n] = 0;
    return out;
}

#include "string_def.h"

char *memcpy(char *dest, char *src, int n)
/*@ With bytes
    Require all_ascii(bytes) && Zlength(bytes) == n &&
            0 <= n && n < INT_MAX &&
            CharArray::undef_full(dest, n) * CharArray::full(src, n, bytes)
    Ensure __return == dest &&
           CharArray::full(dest, n, bytes) * CharArray::full(src, n, bytes)
*/
{
  int i = 0;
  /*@ Inv Assert
      all_ascii(bytes) && Zlength(bytes) == n@pre &&
      0 <= n@pre && n@pre < INT_MAX &&
      0 <= i && i <= n@pre &&
      dest == dest@pre && src == src@pre && n == n@pre &&
      CharArray::full(dest@pre, i, sublist(0, i, bytes)) *
      CharArray::undef_seg(dest@pre, i, n@pre) *
      CharArray::full(src@pre, n@pre, bytes)
  */
  while (i < n) {
    dest[i] = src[i];
    i++;
  }
  return dest;
}

char *memmove(char *dest, char *src, int n)
/*@ With bytes
    Require all_ascii(bytes) && Zlength(bytes) == n &&
            0 <= n && n < INT_MAX &&
            CharArray::undef_full(dest, n) * CharArray::full(src, n, bytes)
    Ensure __return == dest &&
           CharArray::full(dest, n, bytes) * CharArray::full(src, n, bytes)
*/
{
  if (dest < src) {
    int i = 0;
    /*@ Inv Assert
        all_ascii(bytes) && Zlength(bytes) == n@pre &&
        0 <= n@pre && n@pre < INT_MAX &&
        0 <= i && i <= n@pre &&
        dest == dest@pre && src == src@pre && n == n@pre &&
        CharArray::full(dest@pre, i, sublist(0, i, bytes)) *
        CharArray::undef_seg(dest@pre, i, n@pre) *
        CharArray::full(src@pre, n@pre, bytes)
    */
    while (i < n) {
      dest[i] = src[i];
      i++;
    }
  } else {
    int i = n;
    /*@ Inv Assert
        all_ascii(bytes) && Zlength(bytes) == n@pre &&
        0 <= n@pre && n@pre < INT_MAX &&
        0 <= i && i <= n@pre &&
        dest == dest@pre && src == src@pre && n == n@pre &&
        CharArray::undef_seg(dest@pre, 0, i) *
        CharArray::full(dest@pre + i * sizeof(char), n@pre - i,
                        sublist(i, n@pre, bytes)) *
        CharArray::full(src@pre, n@pre, bytes)
    */
    while (i > 0) {
      i--;
      dest[i] = src[i];
    }
  }
  return dest;
}

char *memset(char *s, int c, int n)
/*@ Require 0 <= n && n < INT_MAX &&
            0 <= c && c <= 127 &&
            CharArray::undef_full(s, n)
    Ensure __return == s && CharArray::full(s, n, repeat_Z(c, n))
*/
{
  int i = 0;
  /*@ Inv Assert
      0 <= n@pre && n@pre < INT_MAX &&
      0 <= c@pre && c@pre <= 127 &&
      0 <= i && i <= n@pre &&
      s == s@pre && c == c@pre && n == n@pre &&
      CharArray::full(s@pre, i, repeat_Z(c@pre, i)) *
      CharArray::undef_seg(s@pre, i, n@pre)
  */
  while (i < n) {
    s[i] = c;
    i++;
  }
  return s;
}
